import React, { useState } from 'react';
import * as XLSX from 'xlsx';
import axios from 'axios';
import { UploadCloud, Loader2, FileSpreadsheet } from 'lucide-react';
import { generarNombreImagen } from '../utils/helpers';

const CargaMasiva = ({ localId, onComplete }) => {
  const [loading, setLoading] = useState(false);

  const handleFileUpload = (e) => {
    const file = e.target.files[0];
    if (!file || !localId) return;

    setLoading(true);
    const reader = new FileReader();

    reader.onload = async (event) => {
      try {
        const bstr = event.target.result;
        const wb = XLSX.read(bstr, { type: 'binary' });
        const ws = wb.Sheets[wb.SheetNames[0]];
        const data = XLSX.utils.sheet_to_json(ws);

        const productosProcesados = data.map(prod => ({
          producto: `${prod.tipo} ${prod.marca} ${prod.contenido}`,
          categoria: prod.categoria || 'Almacén',
          precioNuevo: Number(prod.precioNuevo),
          precioViejo: Number(prod.precioViejo),
          stock: Number(prod.stock || 0),
          peso: Number(prod.peso || 0),
          fechaVencimiento: prod.fechaVencimiento,
          // Vincular con la imagen en Cloudinary usando el helper
          publicId: generarNombreImagen(prod.tipo, prod.marca, prod.contenido),
          local: localId
        }));

        await axios.post(`${process.env.REACT_APP_API_URL}/api/ofertas/bulk`, {
          productos: productosProcesados,
          localId: localId
        });

        alert(`✅ Éxito: ${data.length} productos cargados.`);
        if (onComplete) onComplete();
      } catch (error) {
        console.error(error);
        alert("❌ Error en el formato. Columnas: tipo, marca, contenido, categoria, precioNuevo, precioViejo, stock, fechaVencimiento");
      } finally {
        setLoading(false);
      }
    };
    reader.readAsBinaryString(file);
  };

  return (
    <div style={cardStyle}>
      <div style={{display:'flex', alignItems:'center', gap:'10px', marginBottom:'10px'}}>
        <FileSpreadsheet size={20} color="#0284c7"/>
        <h4 style={{margin:0, color:'#0369a1'}}>Carga masiva desde Excel</h4>
      </div>
      <label style={{ ...dropZone, opacity: loading ? 0.6 : 1 }}>
        {loading ? <Loader2 className="animate-spin" /> : <UploadCloud size={24} color="#0284c7" />}
        <span style={{ fontWeight: 'bold', fontSize: '0.85rem' }}>
          {loading ? 'Procesando archivo...' : 'Seleccionar archivo .xlsx'}
        </span>
        <input type="file" accept=".xlsx, .xls" onChange={handleFileUpload} style={{ display: 'none' }} disabled={loading} />
      </label>
    </div>
  );
};

const cardStyle = { background: '#f0f9ff', padding: '20px', borderRadius: '18px', border: '1px solid #bae6fd', marginBottom: '25px' };
const dropZone = { display: 'flex', alignItems: 'center', justifyContent: 'center', gap: '12px', cursor: 'pointer', padding: '20px', background: 'white', borderRadius: '12px', border: '2px dashed #7dd3fc', transition: '0.2s' };

export default CargaMasiva;
